   145 |       MaskVal |= (IsEq ? (Mask_NotAllZeros | AMask_NotMixed)
   146 |                        : (Mask_AllZeros | AMask_Mixed));
   147 |   } else if (ConstA && ConstC && ConstC->isSubsetOf(*ConstA)) {
